package pe.edu.utp.tmo.security; import org.springframework.security.core.userdetails.*; import org.springframework.stereotype.Service; import pe.edu.utp.tmo.dao.UsuarioDAO; @Service public class CustomUserDetailsService implements UserDetailsService{ private final UsuarioDAO dao; public CustomUserDetailsService(UsuarioDAO dao){this.dao=dao;} public UserDetails loadUserByUsername(String username){return dao.buscarPorCorreo(username).map(UserPrincipal::new).orElseThrow(()->new UsernameNotFoundException("Usuario no encontrado"));} }